select a.id, a.order_no,a.currency_id,a.item_id,a.chain_tag,a.item_name,a.user_id,a.tg_user_id, a.channel_id,a.shareholder_id, a.order_type,a.amount,a.bonus_amount,
a.exchange_type,a.trade_img,a.remark,a.address,a.create_time,a.create_by,a.lower_subtype
from t_order_person a

    and a.order_no = #{orderNo}
    and a.currency_id = #{currencyId}
    and a.item_id = #{itemId}
    and a.chain_tag = #{chainTag}
    and a.item_name like concat('%', #{itemName}, '%')
    and a.user_id = #{userId}
    and a.tg_user_id = #{tgUserId}
    and a.order_type = #{orderType}

        AND a.bonus_amount IS NOT NULL AND a.bonus_amount > 0



        AND a.amount >= #{leasAmounts}


        AND a.amount <= #{maxAmounts}


        AND a.amount = 0


        AND a.amount != 0


    and a.exchange_type = #{exchangeType}
    and a.address = #{address}

        and (


                a.create_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )

    and a.create_by = #{createBy}
    and a.lower_subtype = #{lowerSubtype}
    and a.channel_id = #{channelId}
    and a.shareholder_id = #{shareholderId}

        and a.channel_id IN

            #{item}



ORDER BY a.create_time DESC

