select
p.order_type,p.amount,p.bonus_amount,p.lower_subtype
from t_order_person p


    and p.channel_id = #{channelId}


    and  p.currency_id=#{id}


    AND p.create_time  BETWEEN #{startTime} AND #{endTime}

select
count(p.id) as counts,
IFNULL(SUM(p.amount), 0) AS amount,
IFNULL(SUM(p.bonus_amount), 0) AS bonusAmount
from t_order_person p


        and p.channel_id = #{channelId}


        and  p.currency_id=#{id}


        AND p.create_time  BETWEEN #{startTime} AND #{endTime}

    and p.order_type = 1

select
count(p.id) as counts,
IFNULL(SUM(p.amount), 0) AS amount
from t_order_person p


        and p.channel_id = #{channelId}


        and  p.currency_id=#{id}


        AND p.create_time  BETWEEN #{startTime} AND #{endTime}

    and p.order_type = 2
    and p.lower_subtype = #{type}

select p.user_id
from t_order_person p

    -- 充值金额大于0才算
    p.amount > 0

        and p.channel_id = #{channelId}


        and p.currency_id=#{id}

    and p.order_type = 1

        and p.create_time BETWEEN #{startTime} AND #{endTime}

select p.user_id
from t_order_person p


    and  p.channel_id = #{channelId}


    and  p.currency_id=#{id}

and p.order_type = 2
and p.lower_subtype = 1


    AND  p.create_time  BETWEEN #{startTime} AND #{endTime}

select COUNT(CASE WHEN order_type = 1 THEN 1 END) as customerRechargeNum, IFNULL(SUM(CASE WHEN order_type = 1 THEN amount ELSE 0 END),0) as customerRechargeAmount, IFNULL(SUM(CASE WHEN order_type = 1 THEN bonus_amount ELSE 0 END),0) as customerBonusAmount,
COUNT(CASE WHEN order_type = 2 AND lower_subtype = 1 THEN 1 END) as customerRealCashWithdrawalNum, IFNULL(SUM(CASE WHEN order_type = 2 AND lower_subtype = 1 THEN amount ELSE 0 END),0) as customerRealCashWithdrawalAmount,
COUNT(CASE WHEN order_type = 2 AND lower_subtype = 2 THEN 1 END) as customerPointsDeductedNum, IFNULL(SUM(CASE WHEN order_type = 2 AND lower_subtype = 2 THEN amount ELSE 0 END),0) as customerPointsDeductedAmount
from t_order_person
AND user_id = #{userId}
AND currency_id = #{currencyId}
AND create_time BETWEEN #{startTime} AND #{endTime}

